\begin{proof}
    From the fact that $(x(z)-x(a_s))d_z\log(z-a_s)$ is a holomorphic form at $z\to a_s$, one can conclude for that for any $k\geq1$:
   \footnotesize{\begin{align*}
        &F(z)\bigg(d_z\frac{1}{dx(z)}\bigg)^k\bigg((x(z)-x(a_s))d_z\log(z-a_s)\bigg)\\
        &=(k-1) F(z) \bigg(d_z\frac{1}{dx(z)}\bigg)^{k-1}d_z\log(z-a_s)+F(z)\bigg(d_z\frac{1}{dx(z)}\bigg)\bigg[(x(z)-x(a_s))\bigg(d_z\frac{1}{dx(z)}\bigg)^{k-1 }d_z\log(z-a_s)\bigg]\\
        &=O\left((z-a_s)^0dz\right)
    \end{align*}}
    \normalsize{is} a regular one-form at $z\to a_s$ and thus has a vanishing residue. Taking $k=2h$ and multiplying with $[\hbar^{2h}]\frac{y_{a_s}}{\mathcal{S}(\hbar y_{a_s}^{-1})}$, the meromorphic form $\omega_{h,1}$ can be reconstructed locally around $z\to a_s$ in the integrand. Thus, we get the following identity:
    \begin{align*}
        0=\Res_{z\to a_s} \bigg((2h-1)F(z)\omega_{h,1}(z)+F(z) d_z\Big[(x(z)-x(a_s)) \frac{\omega_{h,1}(z)}{dx(z)}\Big]\bigg),
    \end{align*}
    which is equivalent to \eqref{lemma1eq}. It is then straightforward to see that \eqref{lemma2eq} follows from the action of $d_z$ and integration by parts.
\end{proof}

